#include<cstdio>
#include<algorithm>
#include<cstring>
using namespace std;
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c) 
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
typedef long long LL;
const int N=1e5+10,BK=256,BB=N/BK+10;
//const int N=100,BK=3,BB=N/BK+10;//debug
int ql[BB],qr[BB],loc[N],C[BB][N],blk,r,pre[N],suf[N];LL S[BB][BB];
int n,Q,a[N];struct NN{int p,v;}b[N];
namespace BIT
{
	int t[N];inline int qry(int p){int a=0;while(p)a+=t[p],p^=(p&-p);return a;}
	inline void add(int p){while(p<=n)++t[p],p+=(p&-p);}
	inline void del(int p){while(p<=n)--t[p],p+=(p&-p);}
}
using BIT::qry;using BIT::add;using BIT::del;
inline LL Count(int l,int r)
{
	LL ans=0;drep(r,l,i){ans+=qry(a[i]);add(a[i]);}
	rep(l,r,i)del(a[i]);return ans;
}
int main()
{
	n=read();Q=read();rep(1,n,i)a[i]=read(),loc[i]=(i-1)/BK+1;
	blk=loc[n];rep(1,blk,i)ql[i]=qr[i-1]+1,qr[i]=i*BK;qr[blk]=n;
	rep(1,blk,R)
	{
		rep(ql[R],qr[R],i)b[i]=(NN){i,a[i]},++C[R][a[i]];
		sort(b+ql[R],b+qr[R]+1,[&](const NN&x,const NN&y){return x.v<y.v;});
		
		LL &ans=S[R][R];
		add(a[ql[R]]);pre[ql[R]]=0;
		rep(ql[R]+1,qr[R],i){ans+=i-ql[R]-qry(a[i]);pre[i]=ans;add(a[i]);}
		rep(ql[R],qr[R],i)del(a[i]);
		suf[qr[R]]=0;add(a[qr[R]]);
		drep(qr[R]-1,ql[R],i){suf[i]=suf[i+1]+qry(a[i]);add(a[i]);}
		rep(ql[R],qr[R],i)del(a[i]); 
//		printf("S %d :: %lld\n",R,S[R][R]);
		
		drep(R-1,1,L)
		{
			LL &res=S[L][R]=S[L+1][R]+S[L][R-1]-S[L+1][R-1];
			int p=ql[R];rep(ql[L],qr[L],i){while(p<=qr[R]&&b[p].v<b[i].v)++p;res+=p-ql[R];}
		}
		if(R!=blk)memcpy(C[R+1],C[R],(n+3)<<2);rep(2,n,i)C[R][i]+=C[R][i-1];
	}
	LL ans=0;while(Q--)
	{
//		ans=0;//debug
		int l=read()^ans,r=read()^ans,L=loc[l],R=loc[r];
		if(L==R)printf("%lld\n",ans=Count(l,r));
		else
		{
			//[l,qr[L]] --> [l,qr[L]] && [ql[R],r] --> [ql[R],r] && {L+1} <-> {R-1}
			ans=S[L+1][R-1]+suf[l]+pre[r];int p=ql[R],tmp=0;
//			printf("S[L+1][R-1] = %lld\n",S[L+1][R-1]);
//			printf("suf[l] = %d\n",suf[l]);
//			printf("pre[r] = %d\n",pre[r]);
//			printf("case 1 :: %lld\n",ans);
			//[l,qr[L]] --> [ql[R],r]
			rep(ql[L],qr[L],i)if(b[i].p>=l){while(p<=qr[R]&&b[p].v<b[i].v)if(b[p++].p<=r)++tmp;ans+=tmp;}
//			printf("case 2 :: %lld\n",ans);
			//[l,qr[L]] --> [{L+1},{R-1}] && [ql[R],r] --> [{L+1},{R-1}]
			rep(l,qr[L],i)ans+=(C[R-1][a[i]]-C[L][a[i]]);
//			printf("case 3 :: %lld\n",ans);
			rep(ql[R],r,i)ans+=(qr[R-1]-qr[L])-(C[R-1][a[i]]-C[L][a[i]]);
			printf("%lld\n",ans);
		}
	}
	return 0;
}
